-- ============================================================================
-- ZONO — Automation Library OS (system template library)
-- ----------------------------------------------------------------------------
-- Extends automation_templates with the rich library model and seeds the full
-- system library of predefined smart workflow templates (organization_id NULL =
-- system template). Idempotent: upsert by template_key. Safe-by-default — only
-- risk_level='safe' rows are default_enabled. No autonomous external comms.
-- ============================================================================

alter table public.automation_templates
  add column if not exists organization_id uuid references public.organizations(id) on delete cascade,
  add column if not exists subcategory text,
  add column if not exists title_hebrew text,
  add column if not exists description_hebrew text,
  add column if not exists business_goal_hebrew text,
  add column if not exists conditions jsonb not null default '[]'::jsonb,
  add column if not exists actions jsonb not null default '[]'::jsonb,
  add column if not exists priority integer not null default 3,
  add column if not exists risk_level text,
  add column if not exists default_enabled boolean not null default false,
  add column if not exists required_role text not null default 'agent',
  add column if not exists related_modules text[] not null default '{}',
  add column if not exists decision_brain_signal_type text,
  add column if not exists expected_impact text,
  add column if not exists expected_revenue_impact integer not null default 0,
  add column if not exists expected_time_saved_minutes integer not null default 0,
  add column if not exists audit_level text not null default 'standard',
  add column if not exists metadata jsonb not null default '{}'::jsonb,
  add column if not exists updated_at timestamptz not null default now();

create index if not exists automation_templates_lib_idx on public.automation_templates(category, risk_level);
create index if not exists automation_templates_org_idx on public.automation_templates(organization_id);

alter table public.automation_steps drop constraint if exists automation_steps_action_chk;
alter table public.automation_steps add constraint automation_steps_action_chk check (action_type in (
  'create_task','create_follow_up','create_recommendation','create_activity',
  'create_alert','assign_user','change_status','create_opportunity',
  'create_decision_signal','create_dashboard_card','create_notification','create_queue_item',
  'request_approval','create_portal_refresh_suggestion','create_distribution_item',
  'create_document_checklist_item','create_signature_request_draft','create_research_request',
  'create_pricing_review','create_routing_review','create_revenue_review','create_manager_alert',
  'create_agent_coaching_signal','create_data_quality_issue','create_audit_log'));

